sp_widget.client_script:
api.controller = function() {
  var c = this;

  c.activeTab = "tables"; // default

  c.goBack = function() {
    window.history.back();
  };
};

sp_widget.css:
/* LAYOUT */
.migration-wrapper {
  display: flex;
  background: #f6f8fb;
}

.dm-sidebar-slot {
  width: 260px;
}

.migration-content {
  flex: 1;
  padding: 30px 40px;
}

/* HEADER */
.page-header h2 {
  font-size: 28px;
  font-weight: 700;
  margin-bottom: 6px;
}

.page-header p {
  color: #6b7280;
  font-size: 15px;
  margin-bottom: 20px;
}

/* CONNECTION */
.connection-banner {
  background: #e8f7ee;
  border: 1px solid #b7e4c7;
  padding: 14px 18px;
  border-radius: 14px;
  color: #1f7a3e;
  font-weight: 500;
  margin-bottom: 25px;
}

.connection-banner .dot {
  height: 10px;
  width: 10px;
  background: #22c55e;
  border-radius: 50%;
  display: inline-block;
  margin-right: 10px;
}

/* TOGGLE CONTAINER */
.browse-toggle {
  margin-bottom: 25px;
}

/* PILL WRAPPER */
.toggle-pill {
  display: inline-flex;
  background: #e5e7eb;
  padding: 4px;
  border-radius: 14px;
}

/* BUTTONS */
.toggle-btn {
  border: none;
  background: transparent;
  padding: 8px 22px;
  border-radius: 12px;
  font-weight: 500;
  display: flex;
  align-items: center;
  gap: 8px;
  cursor: pointer;
  color: #374151;
}

/* ACTIVE STATE */
.toggle-btn.active {
  background: #ffffff;
  box-shadow: 0 2px 6px rgba(0,0,0,0.06);
}

/* TABLE CARD */
.table-card {
  background: #fff;
  border: 1px solid #cfe1ff;
  border-radius: 14px;
  padding: 20px;
  margin-bottom: 20px;
}

.table-top {
  display: flex;
  align-items: center;
  gap: 20px;
  margin-bottom: 15px;
}

.back-btn {
  background: #f3f4f6;
  border: 1px solid #e5e7eb;
  padding: 8px 14px;
  border-radius: 10px;
  cursor: pointer;
}

.table-name {
  font-size: 18px;
  font-weight: 600;
}

.record-count {
  font-size: 14px;
  color: #6b7280;
}

.search-row {
  display: flex;
  gap: 15px;
}

.search-row input {
  flex: 1;
  padding: 12px;
  border-radius: 12px;
  border: 1px solid #e5e7eb;
}

.select-all-btn {
  padding: 10px 18px;
  border-radius: 12px;
  border: 1px solid #d1d5db;
  background: #fff;
  cursor: pointer;
}

/* FILTER CARD */
.filter-card {
  background: #fff;
  border: 1px solid #cfe1ff;
  border-radius: 14px;
  padding: 20px;
  display: flex;
  align-items: center;
  gap: 20px;
}

.filter-btn {
  padding: 8px 14px;
  border-radius: 10px;
  border: 1px solid #e5e7eb;
  background: #f9fafb;
  cursor: pointer;
}

.filter-title {
  font-weight: 600;
}

.filter-sub {
  font-size: 14px;
  color: #6b7280;
}

sp_widget.script:
(function() {

  data.side = $sp.getWidget('dmm_sidebar');

  data.instanceName = "Production Instance";
  data.instanceUrl = "https://prod.service-now.com";

  data.tableLabel = "Incident";
  data.count = 5;

})();
